<?php session_start(); require 'includes/header.php'; require_login(); if(role()!='Administrator'){ echo '<h1>Access denied</h1>'; require 'includes/footer.php'; exit; } $rows=$pdo->query('SELECT l.*,u.full_name FROM activity_logs l LEFT JOIN users u ON u.id=l.user_id ORDER BY l.id DESC LIMIT 300')->fetchAll(); ?><h1>Audit Logs</h1><div class="card"><table><tr><th>Date</th><th>User</th><th>Action</th><th>Details</th><th>IP</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['created_at'])?></td><td><?=e($r['full_name'])?></td><td><?=e($r['action'])?></td><td><?=e($r['details'])?></td><td><?=e($r['ip_address'])?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
